import anthropic
import json
import time

client = anthropic.Anthropic()

EXTRACTION_SCHEMA = {
    "type": "object",
    "required": ["title", "slug", "content_type", "summary", "tags", "publication_date"],
    "additionalProperties": False,
    "properties": {
        "title": {"type": "string"},
        "slug": {"type": "string"},
        "content_type": {"type": "string", "enum": ["article", "product", "person", "location", "policy"]},
        "summary": {"type": "string", "maxLength": 500},
        "tags": {"type": "array", "items": {"type": "string"}},
        "publication_date": {"type": ["string", "null"]},
        "confidence_notes": {"type": "string"},
        "missing_fields": {"type": "array", "items": {"type": "string"}}
    }
}

SYSTEM_PROMPT = """You are a structured data extraction specialist.
Given a raw source document, extract the fields defined in the schema.
When a field is uncertain, add it to missing_fields and note the issue
in confidence_notes. Never invent data; use null for genuinely missing values."""

def build_batch_requests(source_records):
    requests = []
    for record_id, source_text in source_records:
        requests.append({
            "custom_id": f"ssg_{record_id}",
            "params": {
                "model": "claude-opus-4-5-20251101",
                "max_tokens": 1024,
                "system": [
                    {
                        "type": "text",
                        "text": SYSTEM_PROMPT,
                        "cache_control": {"type": "ephemeral", "ttl": "1h"}
                    }
                ],
                "messages": [
                    {"role": "user", "content": f"Extract data from: {source_text}"}
                ],
                "tools": [
                    {
                        "name": "extract_page_data",
                        "description": "Extract structured page data",
                        "input_schema": EXTRACTION_SCHEMA
                    }
                ],
                "tool_choice": {"type": "tool", "name": "extract_page_data"}
            }
        })
    return requests

def submit_and_poll(requests, max_wait_minutes=90):
    batch = client.messages.batches.create(requests=requests)
    print(f"Batch {batch.id} submitted: {batch.request_counts.processing} requests")

    start = time.time()
    while True:
        batch = client.messages.batches.retrieve(batch.id)
        if batch.processing_status == "ended":
            break
        elapsed = (time.time() - start) / 60
        if elapsed > max_wait_minutes:
            raise TimeoutError(f"Batch did not finish in {max_wait_minutes} minutes")
        print(f"Status: {batch.processing_status} -- {batch.request_counts.processing} pending")
        time.sleep(30)

    print(f"Complete: {batch.request_counts.succeeded} ok, "
          f"{batch.request_counts.errored} errored")
    return batch

def retrieve_results(batch):
    results = {}
    for result in client.messages.batches.results(batch.id):
        cid = result.custom_id
        if result.result.type == "succeeded":
            for block in result.result.message.content:
                if block.type == "tool_use" and block.name == "extract_page_data":
                    results[cid] = {"status": "ok", "data": block.input}
                    break
        else:
            results[cid] = {"status": "error",
                            "error": str(getattr(result.result, 'error', 'unknown'))}
    return results

import jsonschema

def validate_and_triage(results, schema):
    valid = {}
    repair = []

    for cid, result in results.items():
        record_id = cid.replace("ssg_", "")

        if result["status"] == "error":
            repair.append((record_id, f"API error: {result['error']}"))
            continue

        data = result["data"]

        try:
            jsonschema.validate(data, schema)
        except jsonschema.ValidationError as e:
            repair.append((record_id, f"Schema violation: {e.message}"))
            continue

        if len(data.get("missing_fields", [])) > 2:
            repair.append((record_id, f"Too many missing fields: {data['missing_fields']}"))
            continue

        valid[record_id] = data

    return valid, repair

results = retrieve_results(batch)
valid_records, repair_queue = validate_and_triage(results, EXTRACTION_SCHEMA)
print(f"Valid: {len(valid_records)}, Needs repair: {len(repair_queue)}")

