import contentIndex from '../data/extracted/index.json'

export type PageData = {
  title: string
  slug: string
  content_type: string
  summary: string
  tags: string[]
  publication_date: string | null
}

export function getAllSlugs(): string[] {
  return Object.keys(contentIndex)
}

export function getPageData(slug: string): PageData {
  const record = (contentIndex as Record<string, PageData>)[slug]
  if (!record) throw new Error(`No data for slug: ${slug}`)
  return record
}

// app/[slug]/page.tsx
export async function generateStaticParams() {
  return getAllSlugs().map(slug => ({ slug }))
}

export default function Page({ params }: { params: { slug: string } }) {
  const data = getPageData(params.slug)
  return (
    <article>
      <h1>{data.title}</h1>
      <p>{data.summary}</p>
      <ul>{data.tags.map(tag => <li key={tag}>{tag}</li>)}</ul>
    </article>
  )
}
